import{_ as e,o as a,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"ShitEngine","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function o(r,t,d,l,p,h){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="shitengine" tabindex="-1">ShitEngine <a class="header-anchor" href="#shitengine" aria-label="Permalink to &quot;ShitEngine&quot;">​</a></h1><blockquote><p>写好游戏，而不是写框架。</p></blockquote><p>ShitEngine 是一个基于 <strong>C++20</strong> 的轻量级 2D 游戏引擎。它不依赖 Unity、Unreal、Godot 或任何庞然大物，只踩在 SDL3 的肩膀上从零搭起。场景栈、渲染管线、音频系统、事件总线……游戏需要的基础设施全给你焊好了，你直接往里填玩法就行。</p><h2 id="为什么要用它" tabindex="-1">为什么要用它？ <a class="header-anchor" href="#为什么要用它" aria-label="Permalink to &quot;为什么要用它？&quot;">​</a></h2><p><strong>因为你不想每次写游戏都从 CreateWindow 开始。</strong></p><p>很多&quot;轻量级引擎&quot;实际上还是一大坨——你既依赖它，又不理解它。ShitEngine 的体量让你轻松读完整个源码。想改哪里改哪里，没有黑盒，没有魔法。</p><p><strong>因为像素风游戏值得被认真对待。</strong></p><p>那些 &quot;随手用 Unity 拖个 sprite&quot; 的方案，在像素风下要么图糊了，要么位置抖了。ShitEngine 固定逻辑分辨率 + 最近邻缩放 + 每帧像素对齐，像素画怎么画出来的，游戏里就是什么样。</p><p><strong>因为 CMake FetchContent 只需要一行。</strong></p><div class="language-cmake vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmake</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FetchContent_MakeAvailable(ShitEngine)</span></span></code></pre></div><p>所有依赖自动下载，不用装任何 SDK。你的队友 pull 完代码，cmake 一跑，编译，跑。不需要开会对齐环境。</p><h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h2><p>引擎由三个东西组成，搞懂它们你就搞懂了 ShitEngine：</p><h3 id="🧱-gameobject-—-空壳子" tabindex="-1">🧱 GameObject — 空壳子 <a class="header-anchor" href="#🧱-gameobject-—-空壳子" aria-label="Permalink to &quot;🧱 GameObject — 空壳子&quot;">​</a></h3><p>游戏世界里的一个&quot;东西&quot;。可以是一只史莱姆、一盏路灯、或者一个看不见的触发器。GameObject 本身什么都不干——它只是一个会挂组件的架子。</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 只能通过 Scene 创建</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> player </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scene-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createGameObject</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;player&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h3 id="🧩-component-—-积木块" tabindex="-1">🧩 Component — 积木块 <a class="header-anchor" href="#🧩-component-—-积木块" aria-label="Permalink to &quot;🧩 Component — 积木块&quot;">​</a></h3><p>给 GameObject 镶上组件，它才有了血肉：</p><ul><li><code>TransformComponent</code> — 你在哪、多大、转了多少度</li><li><code>SpriteRenderer</code> — 你长什么样、画什么纹理</li><li><code>CameraComponent</code> — 从哪个角度观察世界</li><li><code>AnimationComponent</code> — 让 sprite 动起来</li><li><code>Behavior</code> — 你自己的游戏逻辑——继承它，重写 <code>onUpdate</code></li></ul><p>每种组件<strong>只能挂一个</strong>（一个对象不会有两份 Transform）。<code>addComponent&lt;T&gt;()</code> 如果已存在就返回已有的。</p><h3 id="⚙️-system-—-车间流水线" tabindex="-1">⚙️ System — 车间流水线 <a class="header-anchor" href="#⚙️-system-—-车间流水线" aria-label="Permalink to &quot;⚙️ System — 车间流水线&quot;">​</a></h3><p>组件是积木块，System 是那条流水线。<code>BehaviorSystem</code> 每帧对所有 Behavior 调 <code>onUpdate</code>，<code>RenderSystem</code> 排好序后逐个渲染。System 有优先级，数值小的先执行。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优先级 0:  BehaviorSystem  →  跑游戏逻辑</span></span>
<span class="line"><span>优先级 100: RenderSystem    →  画画面</span></span></code></pre></div><p>你完全可以写自己的 System 插到中间——物理、寻路、AI，随你。</p><h2 id="核心系统一览" tabindex="-1">核心系统一览 <a class="header-anchor" href="#核心系统一览" aria-label="Permalink to &quot;核心系统一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>干的事</th></tr></thead><tbody><tr><td><strong>Game</strong></td><td>引擎总开关：Init / Run / Destroy</td></tr><tr><td><strong>Window</strong></td><td>窗口管理，别让它关了就行</td></tr><tr><td><strong>Renderer</strong></td><td>逻辑分辨率、缩放、绘制 API 封装</td></tr><tr><td><strong>Time</strong></td><td>告诉你上一帧花了多久（DeltaTime）</td></tr><tr><td><strong>Input</strong></td><td>键盘鼠标 Down / Pressed / Released 三态检测</td></tr><tr><td><strong>Config</strong></td><td><code>settings.json</code> 读配置，没有就默认</td></tr><tr><td><strong>ResourceManager</strong></td><td>纹理/音频/字体自动缓存，不重复加载</td></tr><tr><td><strong>AudioPlayer</strong></td><td>分层音频：master × group × track</td></tr><tr><td><strong>EventBus</strong></td><td>类型安全的事件通信，缓冲队列派发</td></tr><tr><td><strong>SceneManager</strong></td><td>场景栈，推拉替换全延迟执行</td></tr></tbody></table><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li><a href="https://github.com/ShitTeam" target="_blank" rel="noreferrer">GitHub</a></li><li>许可证：Apache License 2.0</li></ul>`,28)])])}const u=e(i,[["render",o]]);export{g as __pageData,u as default};
